# INSIGHT: store (value, min_so_far) at each level — O(1) getMin
class MinStack:
    def __init__(self):
        self.stack = []  # (value, min_at_this_level)
    def push(self, val):
        cur_min = min(val, self.stack[-1][1]) if self.stack else val
        self.stack.append((val, cur_min))
    def pop(self):
        self.stack.pop()
    def top(self):
        return self.stack[-1][0]
    def getMin(self):
        return self.stack[-1][1]
# All operations O(1)  Space: O(n)
